// Package testfixtures provides deterministic, reusable fixtures for
// behavioral end-to-end tests of the execute-bead loop. The fixtures
// install into ExecuteBeadLoopRuntime / ExecuteBeadWorker via the
// existing test-injection seams (ExecuteBeadWorker.Executor and
// ExecuteBeadWorker.Reviewer) so callers do not need to reinvent the
// review-retry plumbing per test.
//
// See SD-024 / TD-024 §Bead 6.5.
package testfixtures

import (
	"context"
	"errors"
	"fmt"
	"sync/atomic"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/evidence"
)

// ReviewFailureRunner produces a deterministic Executor + Reviewer pair
// that drive the "N reviewer failures, then 1 success" scenario against
// a real bead store. Beads 7-9 of SD-024 use this fixture to verify
// that ReviewMaxRetries (and the related threshold knobs) wired through
// .ddx/config.yaml reach the running loop.
//
// Behavior:
//
//   - The executor returned by Executor() always reports
//     ExecuteBeadStatusSuccess with ResultRev fixed to r.ResultRev.
//   - The reviewer returned by Reviewer() returns a typed reviewer
//     error for the first FailUntilCall invocations, then returns
//     a clean APPROVE verdict on every subsequent invocation.
//
// The runner is stateful: invocation counters increment on each call,
// so the same instance must not be shared across parallel subtests.
type ReviewFailureRunner struct {
	// ResultRev is stamped on every executor success report. When empty
	// the runner uses a fixed sentinel value so review-error events
	// scoped by result_rev still group correctly.
	ResultRev string

	// FailureClass is the canonical review-error class returned for
	// failed reviews. Empty falls back to evidence.OutcomeReviewProviderEmpty.
	FailureClass string

	// FailUntilCall is the number of reviewer invocations that fail
	// before the runner switches to APPROVE. Reviewer calls
	// 1..FailUntilCall return a typed error; calls FailUntilCall+1
	// onward return a clean APPROVE.
	FailUntilCall int

	reviewCalls atomic.Int32
	execCalls   atomic.Int32
}

const defaultRunnerResultRev = "deadbeef"

func (r *ReviewFailureRunner) resultRev() string {
	if r.ResultRev == "" {
		return defaultRunnerResultRev
	}
	return r.ResultRev
}

func (r *ReviewFailureRunner) failureClass() string {
	if r.FailureClass == "" {
		return evidence.OutcomeReviewProviderEmpty
	}
	return r.FailureClass
}

// Executor returns an ExecuteBeadExecutor that stamps a successful
// report on every invocation. The report carries ResultRev and a
// stable SessionID derived from the executor's call count so review
// retry counters (which scope by result_rev) behave deterministically.
func (r *ReviewFailureRunner) Executor() agent.ExecuteBeadExecutor {
	return agent.ExecuteBeadExecutorFunc(func(_ context.Context, beadID string) (agent.ExecuteBeadReport, error) {
		n := r.execCalls.Add(1)
		return agent.ExecuteBeadReport{
			BeadID:    beadID,
			Status:    agent.ExecuteBeadStatusSuccess,
			SessionID: fmt.Sprintf("rfr-sess-%d", n),
			ResultRev: r.resultRev(),
		}, nil
	})
}

// Reviewer returns a BeadReviewer that fails the first FailUntilCall
// invocations with a typed reviewer error, then returns APPROVE on
// every subsequent invocation. The error path mirrors production
// failingReviewer shape (FEAT-022 §12 taxonomy): a non-nil error plus
// a *ReviewResult whose Error field carries the canonical class.
func (r *ReviewFailureRunner) Reviewer() agent.BeadReviewer {
	return agent.BeadReviewerFunc(func(_ context.Context, _, resultRev, _, _ string) (*agent.ReviewResult, error) {
		n := int(r.reviewCalls.Add(1))
		if n <= r.FailUntilCall {
			class := r.failureClass()
			return &agent.ReviewResult{
					Verdict:   agent.VerdictBlock,
					Error:     class,
					ResultRev: resultRev,
				}, fmt.Errorf("review-failure-runner: %s: %w", class,
					errors.New("simulated reviewer failure"))
		}
		return &agent.ReviewResult{
			Verdict:   agent.VerdictApprove,
			Rationale: "review-failure-runner: APPROVE",
			ResultRev: resultRev,
		}, nil
	})
}

// ReviewCalls returns the cumulative number of reviewer invocations.
func (r *ReviewFailureRunner) ReviewCalls() int {
	return int(r.reviewCalls.Load())
}

// ExecCalls returns the cumulative number of executor invocations.
func (r *ReviewFailureRunner) ExecCalls() int {
	return int(r.execCalls.Load())
}

package testfixtures

import (
	"context"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/evidence"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestReviewFailureRunner verifies the fixture's contract: configured to
// fail N times then approve, driving real loop iterations against a real
// bead.Store produces N review-error events plus one APPROVE event, with
// the bead closed at the end. This is the integration shape beads 7-9
// build on top of when behavioral-testing ReviewMaxRetries flow from
// .ddx/config.yaml.
func TestReviewFailureRunner(t *testing.T) {
	const (
		failUntil    = 2
		threshold    = 5 // > failUntil + 1 so the fixture's APPROVE wins.
		beadID       = "ddx-rfr-001"
		fixedRev     = "deadbeefdeadbeef"
		failureClass = evidence.OutcomeReviewProviderEmpty
	)

	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())
	require.NoError(t, store.Create(&bead.Bead{ID: beadID, Title: "rfr smoke", Priority: 0}))

	runner := &ReviewFailureRunner{
		ResultRev:     fixedRev,
		FailureClass:  failureClass,
		FailUntilCall: failUntil,
	}

	worker := &agent.ExecuteBeadWorker{
		Store:    store,
		Executor: runner.Executor(),
		Reviewer: runner.Reviewer(),
	}

	cfg := config.NewTestConfigForLoop(config.TestLoopConfigOpts{
		Assignee:                "rfr-worker",
		ReviewMaxRetries:        threshold,
		NoProgressCooldown:      time.Hour,
		MaxNoChangesBeforeClose: 3,
		HeartbeatInterval:       time.Hour, // long enough not to fire under Once=true
		EvidenceCaps:            *evidence.DefaultCaps().Config(),
	})
	rcfg := cfg.Resolve(config.TestLoopOverrides(config.TestLoopConfigOpts{
		Assignee: "rfr-worker",
	}))

	runtime := agent.ExecuteBeadLoopRuntime{
		Once:        true,
		ProjectRoot: t.TempDir(),
	}

	const totalIterations = failUntil + 1
	for i := 0; i < totalIterations; i++ {
		_, err := worker.RunWithConfig(context.Background(), rcfg, runtime)
		require.NoErrorf(t, err, "iteration %d: RunWithConfig", i+1)
		// On a reviewer-error iteration the loop intentionally leaves
		// the bead claimed (no Close, no Reopen) so the next iteration
		// in production retries the same result_rev. Tests drive that
		// re-pickup by unclaiming between iterations.
		if i < totalIterations-1 {
			require.NoError(t, store.Unclaim(beadID), "iteration %d: unclaim", i+1)
		}
	}

	assert.Equal(t, totalIterations, runner.ReviewCalls(),
		"reviewer must be invoked once per driven iteration")
	assert.Equal(t, totalIterations, runner.ExecCalls(),
		"executor must be invoked once per driven iteration")

	events, err := store.Events(beadID)
	require.NoError(t, err)

	var (
		reviewErrorCount    int
		reviewApproveCount  int
		manualRequiredCount int
	)
	for _, ev := range events {
		switch ev.Kind {
		case "review-error":
			reviewErrorCount++
			assert.Contains(t, ev.Body, "failure_class="+failureClass,
				"review-error body must carry the configured failure_class")
			assert.Contains(t, ev.Body, "result_rev="+fixedRev,
				"review-error body must scope to the runner's result_rev")
		case "review":
			if ev.Summary == "APPROVE" {
				reviewApproveCount++
			}
		case "review-manual-required":
			manualRequiredCount++
		}
	}

	assert.Equal(t, failUntil, reviewErrorCount,
		"exactly FailUntilCall review-error events must be observable")
	assert.Equal(t, 1, reviewApproveCount,
		"the (FailUntilCall+1)th iteration must record an APPROVE review event")
	assert.Equal(t, 0, manualRequiredCount,
		"with threshold > FailUntilCall+1 no review-manual-required must fire")

	got, err := store.Get(beadID)
	require.NoError(t, err)
	assert.Equal(t, "closed", got.Status,
		"after APPROVE the loop must close the bead via CloseWithEvidence")
}

// TestReviewFailureRunner_ThresholdEscalation confirms the same fixture
// exposes the inverse threshold behavior: when the configured
// ReviewMaxRetries is reached before the runner switches to APPROVE,
// the loop emits the terminal review-manual-required event. This
// mirrors the production failure path beads 7-9 verify against real
// .ddx/config.yaml values.
func TestReviewFailureRunner_ThresholdEscalation(t *testing.T) {
	const (
		failUntil = 3
		threshold = 2 // first 2 failures consume the budget; 2nd trips terminal.
		beadID    = "ddx-rfr-002"
	)

	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())
	require.NoError(t, store.Create(&bead.Bead{ID: beadID, Title: "rfr threshold", Priority: 0}))

	runner := &ReviewFailureRunner{
		FailUntilCall: failUntil,
		FailureClass:  evidence.OutcomeReviewTransport,
	}

	worker := &agent.ExecuteBeadWorker{
		Store:    store,
		Executor: runner.Executor(),
		Reviewer: runner.Reviewer(),
	}

	cfg := config.NewTestConfigForLoop(config.TestLoopConfigOpts{
		Assignee:                "rfr-worker",
		ReviewMaxRetries:        threshold,
		NoProgressCooldown:      time.Hour,
		MaxNoChangesBeforeClose: 3,
		HeartbeatInterval:       time.Hour,
		EvidenceCaps:            *evidence.DefaultCaps().Config(),
	})
	rcfg := cfg.Resolve(config.TestLoopOverrides(config.TestLoopConfigOpts{
		Assignee: "rfr-worker",
	}))

	runtime := agent.ExecuteBeadLoopRuntime{
		Once:        true,
		ProjectRoot: t.TempDir(),
	}

	// Drive iterations until the threshold trips. The first failure
	// emits review-error (attempt_count=1); the second trips the
	// configured threshold and emits review-manual-required, parking
	// the bead via SetExecutionCooldown.
	for i := 0; i < threshold; i++ {
		_, err := worker.RunWithConfig(context.Background(), rcfg, runtime)
		require.NoErrorf(t, err, "iteration %d", i+1)
		if i < threshold-1 {
			require.NoError(t, store.Unclaim(beadID))
		}
	}

	events, err := store.Events(beadID)
	require.NoError(t, err)

	var manual *bead.BeadEvent
	for i := range events {
		if events[i].Kind == "review-manual-required" {
			manual = &events[i]
			break
		}
	}
	require.NotNil(t, manual,
		"with ReviewMaxRetries=%d the threshold-th failure must emit review-manual-required", threshold)
}

